import os
import glob
import json
import pickle
import hashlib
from dataclasses import dataclass
from typing import List, Dict, Any, Optional, Tuple

import numpy as np

try:
    import faiss  # type: ignore
except Exception as e:
    raise ImportError("faiss is required. Install with: pip install faiss-cpu") from e

try:
    from sentence_transformers import SentenceTransformer  # type: ignore
except Exception as e:
    raise ImportError("sentence-transformers is required. Install with: pip install sentence-transformers") from e

try:
    from openai import OpenAI  # type: ignore
except Exception:
    OpenAI = None


@dataclass
class DocumentChunk:
    doc_id: str
    source: str
    chunk_id: int
    text: str
    metadata: Dict[str, Any]


class DocumentLoader:
    def __init__(self, data_dir: str, file_extensions: Optional[List[str]] = None):
        self.data_dir = data_dir
        self.file_extensions = file_extensions or [".txt", ".md", ".html", ".htm", ".json"]

    def load_documents(self) -> List[Dict[str, Any]]:
        docs = []
        patterns = []
        for ext in self.file_extensions:
            patterns.append(os.path.join(self.data_dir, f"**/*{ext}"))
        files = []
        for pattern in patterns:
            files.extend(glob.glob(pattern, recursive=True))
        files = sorted(set(files))
        for path in files:
            try:
                text = self._read_file(path)
                if text and text.strip():
                    docs.append({
                        "source": os.path.abspath(path),
                        "text": text,
                        "metadata": {
                            "filename": os.path.basename(path),
                            "extension": os.path.splitext(path)[1].lower(),
                        },
                    })
            except Exception:
                continue
        return docs

    def _read_file(self, path: str) -> str:
        ext = os.path.splitext(path)[1].lower()
        with open(path, "r", encoding="utf-8", errors="ignore") as f:
            content = f.read()
        if ext in [".html", ".htm"]:
            return self._strip_html(content)
        if ext == ".json":
            try:
                obj = json.loads(content)
                return json.dumps(obj, ensure_ascii=False, indent=2)
            except Exception:
                return content
        return content

    def _strip_html(self, html: str) -> str:
        try:
            from bs4 import BeautifulSoup  # type: ignore
            soup = BeautifulSoup(html, "html.parser")
            return soup.get_text(separator="\n")
        except Exception:
            return html


class TextChunker:
    def __init__(self, chunk_size: int = 1000, chunk_overlap: int = 150):
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap

    def chunk_text(self, text: str) -> List[str]:
        text = text.replace("\r\n", "\n").strip()
        if not text:
            return []
        chunks = []
        start = 0
        n = len(text)
        while start < n:
            end = min(start + self.chunk_size, n)
            if end < n:
                split = text.rfind("\n", start, end)
                if split != -1 and split > start + self.chunk_size // 2:
                    end = split
            chunk = text[start:end].strip()
            if chunk:
                chunks.append(chunk)
            if end >= n:
                break
            start = max(end - self.chunk_overlap, start + 1)
        return chunks


class VectorStore:
    def __init__(self, index_path: str, metadata_path: str, embedding_model_name: str = "sentence-transformers/all-MiniLM-L6-v2"):
        self.index_path = index_path
        self.metadata_path = metadata_path
        self.embedding_model_name = embedding_model_name
        self.embedder = SentenceTransformer(embedding_model_name)
        self.dimension = self.embedder.get_sentence_embedding_dimension()
        self.index = None
        self.metadata: List[Dict[str, Any]] = []

    def build(self, chunks: List[DocumentChunk]) -> None:
        texts = [c.text for c in chunks]
        embeddings = self.embedder.encode(texts, normalize_embeddings=True, batch_size=32, show_progress_bar=True)
        embeddings = np.array(embeddings, dtype=np.float32)
        self.index = faiss.IndexFlatIP(self.dimension)
        self.index.add(embeddings)
        self.metadata = [
            {
                "doc_id": c.doc_id,
                "source": c.source,
                "chunk_id": c.chunk_id,
                "text": c.text,
                "metadata": c.metadata,
            }
            for c in chunks
        ]

    def save(self) -> None:
        os.makedirs(os.path.dirname(self.index_path) or ".", exist_ok=True)
        faiss.write_index(self.index, self.index_path)
        with open(self.metadata_path, "wb") as f:
            pickle.dump(self.metadata, f)

    def load(self) -> None:
        self.index = faiss.read_index(self.index_path)
        with open(self.metadata_path, "rb") as f:
            self.metadata = pickle.load(f)

    def is_ready(self) -> bool:
        return os.path.exists(self.index_path) and os.path.exists(self.metadata_path)

    def search(self, query: str, top_k: int = 5) -> List[Dict[str, Any]]:
        if self.index is None:
            self.load()
        q_emb = self.embedder.encode([query], normalize_embeddings=True)
        q_emb = np.array(q_emb, dtype=np.float32)
        scores, indices = self.index.search(q_emb, top_k)
        results = []
        for score, idx in zip(scores[0], indices[0]):
            if idx == -1:
                continue
            item = dict(self.metadata[idx])
            item["score"] = float(score)
            results.append(item)
        return results


class RAGSystem:
    def __init__(
        self,
        data_dir: str = "data",
        index_path: str = "vector_store.faiss",
        metadata_path: str = "vector_store_meta.pkl",
        embedding_model_name: str = "sentence-transformers/all-MiniLM-L6-v2",
        chunk_size: int = 1000,
        chunk_overlap: int = 150,
        top_k: int = 5,
        openai_model: str = "gpt-4o-mini",
        system_prompt: str = "You are an internal knowledge base assistant. Use only the provided context to answer. If the answer is not in the context, say you don't know."
    ):
        self.data_dir = data_dir
        self.top_k = top_k
        self.openai_model = openai_model
        self.system_prompt = system_prompt
        self.loader = DocumentLoader(data_dir)
        self.chunker = TextChunker(chunk_size=chunk_size, chunk_overlap=chunk_overlap)
        self.vstore = VectorStore(index_path, metadata_path, embedding_model_name=embedding_model_name)
        self.client = OpenAI() if OpenAI is not None else None

    def _hash_doc(self, source: str, text: str) -> str:
        h = hashlib.sha256()
        h.update(source.encode("utf-8"))
        h.update(text.encode("utf-8"))
        return h.hexdigest()

    def ingest(self) -> None:
        docs = self.loader.load_documents()
        chunks: List[DocumentChunk] = []
        for doc in docs:
            doc_id = self._hash_doc(doc["source"], doc["text"])
            parts = self.chunker.chunk_text(doc["text"])
            for i, part in enumerate(parts):
                chunks.append(DocumentChunk(
                    doc_id=doc_id,
                    source=doc["source"],
                    chunk_id=i,
                    text=part,
                    metadata=doc.get("metadata", {})
                ))
        if not chunks:
            raise ValueError("No documents found to ingest.")
        self.vstore.build(chunks)
        self.vstore.save()

    def retrieve(self, query: str, top_k: Optional[int] = None) -> List[Dict[str, Any]]:
        if not self.vstore.is_ready():
            self.ingest()
        return self.vstore.search(query, top_k=top_k or self.top_k)

    def build_prompt(self, query: str, retrieved: List[Dict[str, Any]]) -> str:
        context_blocks = []
        for i, r in enumerate(retrieved, 1):
            context_blocks.append(
                f"[Document {i}]\nSource: {r.get('source')}\nChunk: {r.get('chunk_id')}\nScore: {r.get('score'):.4f}\nContent:\n{r.get('text')}"
            )
        context = "\n\n".join(context_blocks)
        prompt = (
            f"{self.system_prompt}\n\n"
            f"Context:\n{context}\n\n"
            f"Question: {query}\n\n"
            f"Answer:"
        )
        return prompt

    def answer(self, query: str, top_k: Optional[int] = None) -> Tuple[str, List[Dict[str, Any]]]:
        retrieved = self.retrieve(query, top_k=top_k)
        prompt = self.build_prompt(query, retrieved)
        if self.client is None:
            return prompt, retrieved
        messages = [
            {"role": "system", "content": self.system_prompt},
            {"role": "user", "content": prompt},
        ]
        response = self.client.chat.completions.create(
            model=self.openai_model,
            messages=messages,
            temperature=0.2,
        )
        return response.choices[0].message.content or "", retrieved


def main():
    import argparse

    parser = argparse.ArgumentParser(description="Internal Knowledge Base RAG System")
    parser.add_argument("--data-dir", default="data")
    parser.add_argument("--index-path", default="vector_store.faiss")
    parser.add_argument("--metadata-path", default="vector_store_meta.pkl")
    parser.add_argument("--top-k", type=int, default=5)
    parser.add_argument("--ingest", action="store_true")
    parser.add_argument("--query", type=str, default=None)
    parser.add_argument("--model", type=str, default="gpt-4o-mini")
    args = parser.parse_args()

    rag = RAGSystem(
        data_dir=args.data_dir,
        index_path=args.index_path,
        metadata_path=args.metadata_path,
        top_k=args.top_k,
        openai_model=args.model,
    )

    if args.ingest:
        rag.ingest()
        print("Ingestion complete.")
        return

    if args.query:
        answer, retrieved = rag.answer(args.query)
        print(answer)
        return

    while True:
        try:
            query = input("Query (or 'exit'): ").strip()
        except EOFError:
            break
        if not query or query.lower() in {"exit", "quit"}:
            break
        answer, _ = rag.answer(query)
        print(answer)
        print("-" * 80)


if __name__ == "__main__":
    main()